import java.time.LocalDate;
import java.time.Period;

public class Main {
    public static void main(String[] args) {
        // 今日の日付を取得
        LocalDate today = LocalDate.now();

        // 100日後の日付を計算
        LocalDate hundredDaysLater = today.plusDays(100);

        // 今日と100日後の差を計算
        Period period = Period.between(today, hundredDaysLater);

        // 結果を出力
        System.out.println(period); // 出力例：P100D
    }
}

import java.time.LocalDateTime;

public class Main {
    public static void main(String[] args) {
        // 現在の日時を取得
        LocalDateTime now = LocalDateTime.now();

        // 2時間30分後の日時を計算
        LocalDateTime later = now.plusHours(2).plusMinutes(30);

        // 結果を出力
        System.out.println(later); // 出力例：2023-04-16T15:30:40.123
    }
}

import java.time.LocalDate;
import java.time.temporal.ChronoUnit;

public class Main {
    public static void main(String[] args) {
        // 2つの日付を定義
        LocalDate date1 = LocalDate.parse("2023-04-15");
        LocalDate date2 = LocalDate.parse("2023-06-01");

        // 2つの日付の間の日数を計算
        long daysBetween = ChronoUnit.DAYS.between(date1, date2);

        // 結果を出力
        System.out.println(daysBetween); // 出力：47
    }
}

