import java.time.*;

public class Main {
    public static void main(String[] args) {
        // 今日の日付を取得
        LocalDate today = LocalDate.now();

        // 比較対象の日付を指定
        LocalDate compareDate = LocalDate.of(2024, 12, 25);

        // 日付を比較
        if (today.isBefore(compareDate)) {
            System.out.println("今日の日付は" + compareDate + "より前です"); // 出力例：今日の日付は2024-12-25より前です
        } else {
            System.out.println("今日の日付は" + compareDate + "より後です"); // 出力例：今日の日付は2024-12-25より後です
        }
    }
}

import java.time.*;

public class Main {
    public static void main(String[] args) {
        // 指定した年月のYearMonthインスタンスを作成
        YearMonth yearMonth = YearMonth.of(2024, 2);

        // 月末日を取得
        LocalDate endOfMonth = yearMonth.atEndOfMonth();

        // 月末日を表示
        System.out.println("月末日: " + endOfMonth); // 出力例：月末日: 2024-02-29
    }
}
